import React, { useEffect, useState } from "react";
import { Table, TableCaption, TableHead, TableHeader, TableRow } from "./ui/Table";



const BookList = () => {
  const [books, setBooks] = useState([]);

  useEffect(() => {
    fetch("http://localhost:3000/api/book")
      .then((response) => response.json())
      .then((data) => setBooks(data))
      .catch((error) => console.error("erro for the data fetching ", error));
  }, []);
  return (
    <div>
      <h1 className="text-red-500 text-[50px] text-center">Liste des livres</h1>
      <ul className="flex flex-col items-center justify-center">
        {books.map((book) => (
          <li key={book._id}>
            <h2>{book.title}</h2>
            <p>{book.description}</p>
            <p>Pages : {book.page}</p>
          </li>
        ))}
      </ul>
      <Table>
        <TableCaption>book List</TableCaption>
        <TableHeader>
          <TableRow>
            <TableHead className="w-[100px]">ID</TableHead>
            <TableHead>Title</TableHead>
            <TableHead>description</TableHead>
            <TableHead className="text-right">Nombre des page</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {books.map((book) => (
            <TableRow key={book._id}>
              <TableCell className="font-medium">{book._id}</TableCell>
              <TableCell>{book.title}</TableCell>
              <TableCell>{book.description}</TableCell>
              <TableCell className="text-right">
                {book.page}
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
};

export default BookList;
